public String repeatEnd(String str, int n) {
    if (n > str.length()) {
        n = str.length();
    }
    String end = str.substring(str.length() - n);
    String repeated = "";
    for (int i = 0; i < n; i++) {
        repeated += end;
    }
    return repeated;
}

