        char current = str.charAt(i);
        if (current == 'z') {
            zip = true;
        } else if (current == 'p' && zip) {
            result += "p";
            zip = false;
        } else if (zip) {
            i++;
            zip = false;
        } else {
            result += current;
        }
    }

    return result;
}

